// tgmath.h dispatch should link float and long double math variants.
// expected: exit=0
#include <assert.h>
#include <tgmath.h>

static int near1000(double v, int lo, int hi) {
  int n = (int)(v * 1000.0);
  return n >= lo && n <= hi;
}

static int nanish(long double v) {
  return v != 0.0L && !(v < 0.0L) && !(v > 0.0L);
}

int main(void) {
  float f = 2.0f;
  long double l = 2.0L;
  double z = 0.0;
  double nanv = z / z;
  float asin_fd = asin(2.0f);
  long double asin_ld = asin(2.0L);
  float acos_fd = acos(2.0f);
  long double acos_ld = acos(2.0L);
  float sqrt_fd = sqrt(-1.0f);
  long double sqrt_ld = sqrt(-1.0L);
  float sqrt_fnz = sqrt(-0.0f);
  long double sqrt_linf = sqrt(1.0L / z);
  float pow_fd = pow(-2.0f, 0.5f);
  long double pow_ld = pow(-2.0L, 0.5L);
  float log_fd = log(-1.0f);
  long double log_ld = log(-1.0L);
  float exp_fd = exp((float)nanv);
  long double exp_ld = exp((long double)nanv);
  float sin_fd = sin(1.0f / 0.0f);
  long double cos_ld = cos(1.0L / z);
  float tan_fd = tan(1.0f / 0.0f);
  float modf_fint = 1.0f;
  long double modf_lint = 1.0L;
  int remquo_f_bits = 0;
  int remquo_l_bits = 0;
  float acosh_fd = acosh(0.5f);
  long double atanh_ld = atanh(2.0L);

  assert(near1000(sqrt(f), 1412, 1416));
  assert(near1000(sqrt(l), 1412, 1416));
  assert(sqrt(1.0e20f) > 9.9e9f && sqrt(1.0e20f) < 1.01e10f);
  assert(sqrt(1.0e200L) > 9.9e99L && sqrt(1.0e200L) < 1.01e100L);
  assert(sqrt(1.0e-200L) > 9.9e-101L && sqrt(1.0e-200L) < 1.01e-100L);
  assert(nanish(sqrt_fd));
  assert(nanish(sqrt_ld));
  assert(1.0f / sqrt_fnz < 0.0f);
  assert(sqrt_linf > 1.0e300L);
  assert(near1000(cbrt(27.0f), 2998, 3002));
  assert(near1000(cbrt(-8.0L), -2002, -1998));
  assert(cbrt(1.0f / 0.0f) > 1.0e30f);
  assert(cbrt(-1.0L / 0.0L) < -1.0e300L);
  assert(1.0f / cbrt(-0.0f) < 0.0f);
  assert(nanish(cbrt((float)nanv)));
  assert(cbrt(1.0e30f) > 9.9e9f && cbrt(1.0e30f) < 1.01e10f);
  assert(cbrt(1.0e300L) > 9.9e99L && cbrt(1.0e300L) < 1.01e100L);
  assert(cbrt(-1.0e300L) < -9.9e99L && cbrt(-1.0e300L) > -1.01e100L);

  assert(near1000(sin(1.5707963267948966f), 998, 1002));
  assert(near1000(sin(1.5707963267948966L), 998, 1002));
  assert(nanish(sin_fd));
  assert(near1000(cos(3.141592653589793f), -1002, -998));
  assert(near1000(cos(3.141592653589793L), -1002, -998));
  assert(nanish(cos_ld));
  assert(near1000(tan(0.7853981633974483f), 998, 1002));
  assert(near1000(tan(0.7853981633974483L), 998, 1002));
  assert(nanish(tan_fd));
  assert(sin(10000.0f) == sin(10000.0f) && sin(10000.0f) > -2.0f && sin(10000.0f) < 2.0f);
  assert(cos(10000.0L) == cos(10000.0L) && cos(10000.0L) > -2.0L && cos(10000.0L) < 2.0L);
  assert(tan(10000.0f) == tan(10000.0f) && tan(10000.0f) > -100.0f && tan(10000.0f) < 100.0f);
  assert(near1000(asinh(1.0f), 880, 882));
  assert(near1000(asinh(1.0L), 880, 882));
  assert(1.0f / asinh(-0.0f) < 0.0f);
  assert(asinh(1.0e-20f) > 0.0f && asinh(1.0e-20f) < 2.0e-20f);
  assert(asinh(-1.0e-20L) < 0.0L && asinh(-1.0e-20L) > -2.0e-20L);
  assert(asinh(1.0e200L) > 400.0L && asinh(1.0e200L) < 500.0L);
  assert(asinh(-1.0e200L) < -400.0L && asinh(-1.0e200L) > -500.0L);
  assert(near1000(acosh(2.0f), 1315, 1317));
  assert(near1000(acosh(2.0L), 1315, 1317));
  assert(nanish(acosh_fd));
  assert(acosh(1.0L / z) > 1.0e300L);
  assert(acosh(1.0e200L) > 400.0L && acosh(1.0e200L) < 500.0L);
  assert(near1000(atanh(0.5f), 548, 550));
  assert(near1000(atanh(0.5L), 548, 550));
  assert((int)tanh(1.0f / 0.0f) == 1);
  assert((int)tanh(-1.0L / 0.0L) == -1);
  assert(1.0f / sinh(-0.0f) < 0.0f);
  assert(sinh(1.0e-20f) > 0.0f && sinh(1.0e-20f) < 2.0e-20f);
  assert(sinh(-1.0e-20L) < 0.0L && sinh(-1.0e-20L) > -2.0e-20L);
  assert(1.0f / tanh(-0.0f) < 0.0f);
  assert(tanh(1.0e-20f) > 0.0f && tanh(1.0e-20f) < 2.0e-20f);
  assert(tanh(-1.0e-20L) < 0.0L && tanh(-1.0e-20L) > -2.0e-20L);
  assert(atanh(1.0f) > 1.0e30f);
  assert(nanish(atanh_ld));
  assert(1.0f / atanh(-0.0f) < 0.0f);
  assert(atanh(1.0e-20L) > 0.0L && atanh(1.0e-20L) < 2.0e-20L);
  assert(atanh(-1.0e-20L) < 0.0L && atanh(-1.0e-20L) > -2.0e-20L);

  assert(near1000(asin(1.0f), 1568, 1572));
  assert(near1000(asin(1.0L), 1568, 1572));
  assert(near1000(asin(-1.0f), -1572, -1568));
  assert(1.0f / asin(-0.0f) < 0.0f);
  assert(nanish(asin_fd));
  assert(nanish(asin_ld));
  assert(near1000(acos(-1.0L), 3140, 3143));
  assert(acos(1.0f) == 0.0f && 1.0f / acos(1.0f) > 0.0f);
  assert(near1000(acos(0.0f), 1568, 1572));
  assert(near1000(acos(0.0L), 1568, 1572));
  assert(nanish(acos_fd));
  assert(nanish(acos_ld));
  assert(near1000(atan(1.0f), 783, 787));
  assert(near1000(atan(1.0L), 783, 787));
  assert(near1000(atan(-1.0f), -787, -783));
  assert(1.0f / atan(-0.0f) < 0.0f);
  assert(atan(1.0L / z) > 1.56L && atan(1.0L / z) < 1.58L);
  assert(near1000(atan2(1.0f, 0.0f), 1568, 1572));
  assert(near1000(atan2(1.0L, 0.0L), 1568, 1572));
  assert(1.0f / atan2(-0.0f, 0.0f) < 0.0f);
  assert(near1000(atan2(0.0L, -0.0L), 3140, 3143));
  assert(near1000(atan2(-0.0L, -0.0L), -3143, -3140));
  assert(near1000(atan2(1.0f / 0.0f, -1.0f / 0.0f), 2354, 2358));
  assert(near1000(atan2(-1.0L / 0.0L, -1.0L / 0.0L), -2358, -2354));

  assert(near1000(exp(1.0f), 2716, 2720));
  assert(near1000(exp(1.0L), 2716, 2720));
  assert(exp(1.0f / 0.0f) > 1.0e30f);
  assert(exp(-1.0L / 0.0L) == 0.0L);
  assert(exp(10000.0f) > 1.0e30f);
  assert(exp(-10000.0L) == 0.0L);
  assert(exp2(2000.0f) > 1.0e30f);
  assert(exp2(-2000.0L) == 0.0L);
  assert((int)expm1(-10000.0f) == -1);
  assert(nanish(exp_fd));
  assert(nanish(exp_ld));
  assert(1.0f / expm1(-0.0f) < 0.0f);
  assert(1.0L / expm1(-0.0L) < 0.0L);
  assert(sinh(10000.0f) > 1.0e30f);
  assert(sinh(-10000.0L) < -1.0e300L);
  assert(cosh(10000.0f) > 1.0e30f);
  assert(cosh(-10000.0L) > 1.0e300L);
  assert((int)tanh(10000.0f) == 1);
  assert((int)tanh(-10000.0L) == -1);
  assert(near1000(log(2.718281828459045f), 998, 1002));
  assert(near1000(log(2.718281828459045L), 998, 1002));
  assert(nanish(log_fd));
  assert(nanish(log_ld));
  assert(log(0.0f) < -1.0e30f);
  assert(log(1.0L / z) > 1.0e300L);
  assert(1.0f / log1p(-0.0f) < 0.0f);
  assert(1.0L / log1p(-0.0L) < 0.0L);
  assert(log1p(1.0e-20L) > 0.0L && log1p(1.0e-20L) < 2.0e-20L);
  assert(log1p(-1.0e-20L) < 0.0L && log1p(-1.0e-20L) > -2.0e-20L);
  assert(expm1(1.0e-20L) > 0.0L && expm1(1.0e-20L) < 2.0e-20L);
  assert(expm1(-1.0e-20L) < 0.0L && expm1(-1.0e-20L) > -2.0e-20L);
  assert(near1000(log2(8.0f), 2998, 3002));
  assert(near1000(log2(8.0L), 2998, 3002));
  assert(nanish(log2(-1.0f)));
  assert(near1000(log10(100.0f), 1998, 2002));
  assert(near1000(log10(100.0L), 1998, 2002));
  assert(nanish(log10(-1.0L)));
  assert(near1000(erf(1.0f), 841, 844));
  assert(near1000(erf(1.0L), 841, 844));
  assert(erf(0.0f) == 0.0f && 1.0f / erf(-0.0f) < 0.0f);
  assert(erf(0.0L) == 0.0L && 1.0L / erf(-0.0L) < 0.0L);
  assert(near1000(erfc(1.0f), 156, 158));
  assert(near1000(erfc(1.0L), 156, 158));
  assert(erfc(0.0f) == 1.0f && erfc(-0.0f) == 1.0f);
  assert(erfc(0.0L) == 1.0L && erfc(-0.0L) == 1.0L);
  assert(erfc(5.0f) > 0.0f && erfc(5.0f) < 1.0e-10f);
  assert(erfc(10.0L) > 0.0L && erfc(10.0L) < 1.0e-40L);

  assert((int)floor(2.9L) == 2);
  assert((int)ceil(2.1L) == 3);
  assert((int)round(-2.5L) == -3);
  assert((int)trunc(-2.8f) == -2);
  assert((int)trunc(-2.8L) == -2);
  assert(nanish(floor((float)nanv)));
  assert(ceil(1.0L / z) > 1.0e300L);
  assert(round(-1.0f / 0.0f) < -1.0e30f);
  assert(1.0f / floor(-0.0f) < 0.0f);
  assert(1.0f / trunc(-0.8f) < 0.0f);
  assert(1.0L / ceil(-0.8L) < 0.0L);
  assert(1.0L / round(-0.3L) < 0.0L);
  assert(trunc(10000000000.75) == 10000000000.0);
  assert(floor(-10000000000.75) == -10000000001.0);
  assert(ceil(10000000000.25) == 10000000001.0);
  assert(round(-10000000000.25) == -10000000000.0);
  assert(trunc(1.0e20) == 1.0e20);
  assert(floor(1.0e20) == 1.0e20);
  assert(ceil(-1.0e20) == -1.0e20);
  assert(round(-1.0e20) == -1.0e20);
  assert(nearbyint(2.5f) == 2.0f);
  assert(nearbyint(3.5L) == 4.0L);
  assert(nearbyint(10000000000.5) == 10000000000.0);
  assert(rint(10000000001.5L) == 10000000002.0L);
  assert(rint(2.5f) == 2.0f);
  assert(rint(-3.5L) == -4.0L);
  assert(lrint(3.5f) == 4);
  assert(llrint(-2.5L) == -2);
  assert(lround(2.5f) == 3);
  assert(llround(-2.5L) == -3);
  assert(near1000(fabs(-2.5f), 2498, 2502));
  assert(near1000(fabs(-4.5L), 4498, 4502));
  assert(1.0f / fabs(-0.0f) > 0.0f);
  assert(1.0L / fabs(-0.0L) > 0.0L);
  assert(1.0f / copysign(-0.0f, 1.0f) > 0.0f);
  assert(1.0L / copysign(-0.0L, 1.0L) > 0.0L);

  assert(near1000(pow(2.0f, 5.0f), 31998, 32002));
  assert(near1000(pow(2.0L, 4.0L), 15998, 16002));
  assert(nanish(pow_fd));
  assert(nanish(pow_ld));
  assert((int)pow((float)nanv, 0.0f) == 1);
  assert(pow(0.0L, -0.5L) > 1.0e300L);
  assert(1.0f / pow(-0.0f, 3.0f) < 0.0f);
  assert(pow(-2.0, 10000000000.0) > 1.0e300);
  assert(pow(-2.0, 10000000001.0) < -1.0e300);
  assert(pow(2.0, -10000000000.0) == 0.0);
  assert(1.0 / pow(-2.0, -10000000001.0) < 0.0);
  assert(1.0 / pow(-0.0, 10000000001.0) < 0.0);
  assert(pow(-0.0, -10000000001.0) < -1.0e300);
  assert(near1000(fmod(7.5f, 2.0f), 1498, 1502));
  assert(near1000(fmod(7.5L, 2.0L), 1498, 1502));
  assert(nanish(fmod(7.5f, 0.0f)));
  assert(nanish(fmod(7.5L, 0.0L)));
  assert((int)fmod(7.5f, 1.0f / 0.0f) == 7);
  assert((int)fmod(7.5L, 1.0L / 0.0L) == 7);
  assert(fabs(fmod(1.0e20f, 3.0f)) < 3.0f);
  assert(fmod(-1.0e20L, 3.0L) <= 0.0L && fabs(fmod(-1.0e20L, 3.0L)) < 3.0L);
  assert(fabs(remainder(1.0e20f, 3.0f)) <= 1.5f);
  assert(fabs(remquo(5.5f, 2.0f, &remquo_f_bits)) < 0.51f && remquo_f_bits == 3);
  assert(fabs(remquo(-1.0e20L, 3.0L, &remquo_l_bits)) <= 1.5L);
  assert(1.0f / modf(-0.0f, &modf_fint) < 0.0f && 1.0f / modf_fint < 0.0f);
  assert(1.0L / modf(-2.0L, &modf_lint) < 0.0L && (int)modf_lint == -2);
  assert(near1000(scalbn(0.75f, 4), 11998, 12002));
  assert(near1000(scalbn(0.25L, 6), 15998, 16002));
  assert(near1000(scalbln(1.25f, 2L), 4998, 5002));
  assert(near1000(scalbln(3.0L, -1L), 1498, 1502));
  assert(ldexp(1.0f, 5000) > 1.0e30f);
  assert(1.0L / ldexp(-1.0L, -5000) < 0.0L);
  assert(scalbln(1.0L, 5000L) > 1.0e300L);
  assert(1.0f / scalbln(-1.0f, -5000L) < 0.0f);
  assert(ilogb(0.75f) == -1);
  assert(ilogb(8.0L) == 3);
  assert((int)logb(0.75f) == -1);
  assert((int)logb(8.0L) == 3);
  assert(near1000(hypot(3.0f, 4.0f), 4998, 5002));
  assert(near1000(hypot(3.0L, 4.0L), 4998, 5002));
  assert(hypot(1.0e20f, 1.0e20f) > 1.0e20f);
  assert(hypot(1.0L / z, (long double)nanv) > 1.0e300L);
  assert(nanish(hypot((float)nanv, 3.0f)));
  assert(near1000(fmin(3.0f, 4.0f), 2998, 3002));
  assert(near1000(fmin(3.0L, 4.0L), 2998, 3002));
  assert(near1000(fmax(3.0f, 4.0f), 3998, 4002));
  assert(near1000(fmax(3.0L, 4.0L), 3998, 4002));
  assert((int)fmin((float)nanv, 5.0f) == 5);
  assert((int)fmin(6.0L, (long double)nanv) == 6);
  assert(1.0f / fmin(-0.0f, 0.0f) < 0.0f);
  assert(1.0L / fmin(0.0L, -0.0L) < 0.0L);
  assert((int)fmax((float)nanv, 5.0f) == 5);
  assert((int)fmax(6.0L, (long double)nanv) == 6);
  assert(1.0f / fmax(-0.0f, 0.0f) > 0.0f);
  assert(1.0L / fmax(0.0L, -0.0L) > 0.0L);

  return 0;
}
